const opportunities = $input.all();

const scored = opportunities.map(item => {
  const data = item.json;
  let score = 0;
  let scoreBreakdown = {};

  // AUDIENCE SIZE (0-10 points)
  const attendance = parseInt(data.attendance) || 0;
  if (attendance >= 1000) {
    score += 10;
    scoreBreakdown.audience = '10 (1000+ attendees - Major conference)';
  } else if (attendance >= 500) {
    score += 8;
    scoreBreakdown.audience = '8 (500-999 attendees - Large event)';
  } else if (attendance >= 200) {
    score += 5;
    scoreBreakdown.audience = '5 (200-499 attendees - Mid-size)';
  } else if (attendance >= 50) {
    score += 3;
    scoreBreakdown.audience = '3 (50-199 attendees - Small event)';
  } else {
    score += 1;
    scoreBreakdown.audience = '1 (<50 attendees - Very small)';
  }

  // EVENT TYPE (0-5 points)
  const eventType = data.event_type || '';
  if (eventType === 'conference') {
    score += 5;
    scoreBreakdown.type = '5 (Conference - High prestige)';
  } else if (eventType === 'association') {
    score += 4;
    scoreBreakdown.type = '4 (Association - Industry authority)';
  } else if (eventType === 'university') {
    score += 3;
    scoreBreakdown.type = '3 (University - Thought leadership)';
  } else if (eventType === 'podcast') {
    score += 2;
    scoreBreakdown.type = '2 (Podcast - Content marketing)';
  }

  // AUDIENCE FIT (0-5 points)
  const audienceType = (data.audience_type || '').toLowerCase();
  let fitScore = 0;
  if (audienceType.includes('executive') || audienceType.includes('c-suite')) fitScore += 3;
  if (audienceType.includes('venue') || audienceType.includes('restaurant') || audienceType.includes('hotel')) fitScore += 2;
  if (audienceType.includes('technology') || audienceType.includes('tech')) fitScore += 1;
  fitScore = Math.min(fitScore, 5);
  score += fitScore;
  scoreBreakdown.fit = `${fitScore} (Audience alignment)`;

  // PAST SPEAKERS PRESTIGE (0-3 points)
  const pastSpeakers = data.past_speakers || '';
  if (pastSpeakers.length > 0) {
    // Check for recognizable names/companies
    const prestigious = ['CEO', 'Founder', 'VP', 'Director', 'Harvard', 'MIT', 'Stanford'];
    const hasPrestige = prestigious.some(term => pastSpeakers.includes(term));
    if (hasPrestige) {
      score += 3;
      scoreBreakdown.prestige = '3 (High-profile past speakers)';
    } else {
      score += 1;
      scoreBreakdown.prestige = '1 (Has past speakers)';
    }
  }

  // CFP DEADLINE URGENCY (0-2 points)
  const cfpDeadline = data.cfp_deadline || '';
  if (cfpDeadline.toLowerCase().includes('rolling')) {
    score += 2;
    scoreBreakdown.urgency = '2 (Rolling deadline - No pressure)';
  } else if (cfpDeadline && !cfpDeadline.toLowerCase().includes('closed')) {
    // Check if deadline is in future
    const deadlineDate = new Date(cfpDeadline);
    const now = new Date();
    const daysUntil = Math.floor((deadlineDate - now) / (1000 * 60 * 60 * 24));
    if (daysUntil >= 30) {
      score += 1;
      scoreBreakdown.urgency = '1 (Deadline >30 days away)';
    }
  }

  // DETERMINE STATUS
  let status;
  if (score >= 18) {
    status = 'High Priority - Pursue Aggressively';
  } else if (score >= 12) {
    status = 'Qualified - Standard Outreach';
  } else if (score >= 8) {
    status = 'Low Priority - Nurture';
  } else {
    status = 'Disqualify - Poor Fit';
  }

  return {
    ...data,
    score: score,
    score_breakdown: JSON.stringify(scoreBreakdown),
    status: status,
    last_activity: new Date().toISOString()
  };
});

return scored;

